mapper.select:
SELECT
    (
        SELECT COUNT(1)
        FROM io_order
        WHERE delete_flag = 0
          AND order_type = #{inboundType}
          AND biz_date = #{today}
    ) AS todayInboundCount,
    (
        SELECT COUNT(1)
        FROM io_order
        WHERE delete_flag = 0
          AND order_type = #{outboundType}
          AND biz_date = #{today}
    ) AS todayOutboundCount,
    (
        SELECT COUNT(1)
        FROM product p
        LEFT JOIN inventory i
            ON i.product_id = p.id
           AND i.delete_flag = 0
        WHERE p.delete_flag = 0
          AND p.min_stock > COALESCE(i.total_qty, 0)
    ) AS inventoryShortageWarnCount,
    (
        SELECT COUNT(1)
        FROM io_apply
        WHERE delete_flag = 0
          AND order_type = #{inboundType}
          AND approve_status = #{unapprovedStatus}
    ) AS inboundApplyUnapprovedCount,
    (
        SELECT COUNT(1)
        FROM io_apply
        WHERE delete_flag = 0
          AND order_type = #{outboundType}
          AND approve_status = #{unapprovedStatus}
    ) AS outboundApplyUnapprovedCount
